<?php
require_once __DIR__.'/app/layout.php'; require_admin();$error='';if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();try{if(strlen($_POST['password']??'')<8)throw new RuntimeException('Kata sandi minimal 8 karakter.');$st=db()->prepare('INSERT INTO users(name,username,password_hash,role) VALUES(?,?,?,?)');$st->execute([trim($_POST['name']),trim($_POST['username']),password_hash($_POST['password'],PASSWORD_DEFAULT),$_POST['role']==='admin'?'admin':'operator']);flash('success','Pengguna berhasil ditambahkan.');redirect('users.php');}catch(Throwable $e){$error=$e->getMessage();}}$rows=db()->query('SELECT id,name,username,role,created_at FROM users ORDER BY name')->fetchAll();page_header('Pengguna','users');if($error)echo '<div class="alert error">'.e($error).'</div>';?><div class="grid two-col"><div class="card"><div class="section-title"><h2>Daftar pengguna</h2></div><div class="table-wrap"><table class="data"><thead><tr><th>Nama</th><th>Username</th><th>Peran</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['name'])?></td><td><?=e($r['username'])?></td><td><?=e(ucfirst($r['role']))?></td></tr><?php endforeach;?></tbody></table></div></div><div class="card"><div class="section-title"><h2>Tambah pengguna</h2></div><form method="post"><?=csrf_input()?><div class="field"><label>Nama</label><input name="name" required></div><div class="field" style="margin-top:10px"><label>Username</label><input name="username" required></div><div class="field" style="margin-top:10px"><label>Kata sandi</label><input type="password" name="password" minlength="8" required></div><div class="field" style="margin-top:10px"><label>Peran</label><select name="role"><option value="operator">Operator</option><option value="admin">Admin</option></select></div><div class="form-actions"><button class="btn">Tambah</button></div></form></div></div><?php page_footer();
